<template><section class="manager"><div class="manager__head"><div><span>CUPONS MONITORADOS</span><h2>Descontos e atribuições</h2></div><q-btn unelevated no-caps icon="mdi-ticket-percent-outline" label="Novo cupom" @click="open()" /></div><q-input v-model="search" outlined dense clearable label="Buscar cupom" @keyup.enter="load" /><q-table flat bordered class="manager__table" row-key="_id" :rows="rows" :columns="columns" :loading="loading"><template #body-cell-affiliate="p"><q-td :props="p">{{ p.row.affiliate?.name || '-' }}</q-td></template><template #body-cell-actions="p"><q-td :props="p"><q-btn flat round dense icon="mdi-pencil" @click="open(p.row)" /><q-btn flat round dense color="negative" icon="mdi-delete-outline" @click="remove(p.row)" /></q-td></template></q-table><q-dialog v-model="dialog"><q-card class="manager__dialog"><q-card-section class="row items-center justify-between"><strong>{{ form._id ? 'Editar cupom' : 'Cadastrar cupom' }}</strong><q-btn flat round icon="mdi-close" v-close-popup /></q-card-section><q-card-section><q-form @submit.prevent="save"><q-input v-model="form.title" outlined label="Título único" :rules="[required]" /><q-input v-model="form.description" outlined type="textarea" autogrow label="Descrição" class="q-mt-sm" /><q-input v-model.number="form.discountAmount" outlined type="number" min="0.01" step="0.01" label="Desconto em real" prefix="R$" class="q-mt-sm" :rules="[required]" /><q-select v-model="form.affiliateId" outlined label="Afiliado" :options="affiliateOptions" emit-value map-options class="q-mt-sm" :rules="[required]" /><q-toggle v-model="form.active" label="Cupom ativo" color="secondary" class="q-mt-sm" /><q-btn unelevated no-caps class="manager__cta full-width q-mt-md" type="submit" label="Salvar cupom" :loading="loading" /></q-form></q-card-section></q-card></q-dialog></section></template>
<script setup>
import { computed, onMounted, reactive, ref } from 'vue'; import { useQuasar } from 'quasar'; import { api } from 'boot/axios'
const $q=useQuasar(); const token=localStorage.getItem('aito_admin_token'); const headers={headers:{Authorization:`Bearer ${token}`}}; const rows=ref([]); const affiliates=ref([]); const search=ref(''); const loading=ref(false); const dialog=ref(false); const form=reactive({ title:'',description:'',discountAmount:null,affiliateId:'',active:true,_id:'' }); const columns=[{name:'title',label:'Cupom',field:'title',align:'left'},{name:'affiliate',label:'Afiliado',field:'affiliate',align:'left'},{name:'discountAmount',label:'Desconto',field:'discountAmount',align:'right'},{name:'usageCount',label:'Usos',field:'usageCount',align:'right'},{name:'actions',label:'',align:'right'}]; const affiliateOptions=computed(()=>affiliates.value.map(item=>({label:`${item.name} · ${item.email}`,value:item._id}))); const required=v=>Boolean(String(v||'').trim())||'Obrigatório.'
function reset(){Object.assign(form,{title:'',description:'',discountAmount:null,affiliateId:'',active:true,_id:''})}; function open(item){reset();if(item)Object.assign(form,{...item,affiliateId:item.affiliate?._id||item.affiliate||'',discountAmount:item.discountAmount||0});dialog.value=true}
async function load(){loading.value=true;try{rows.value=(await api.get('/admin/coupons',{...headers,params:{q:search.value}})).data.data||[];affiliates.value=(await api.get('/admin/affiliates',headers)).data.data||[]}catch(e){$q.notify({type:'negative',message:e.response?.data?.message||'Falha ao carregar cupons.'})}finally{loading.value=false}};async function save(){loading.value=true;try{if(form._id)await api.put(`/admin/coupons/${form._id}`,form,headers);else await api.post('/admin/coupons',form,headers);dialog.value=false;await load();$q.notify({type:'positive',message:'Cupom salvo.'})}catch(e){$q.notify({type:'negative',message:e.response?.data?.message||'Falha ao salvar cupom.'})}finally{loading.value=false}};function remove(item){$q.dialog({title:'Excluir cupom',message:`Remover ${item.title}?`,cancel:true}).onOk(async()=>{await api.delete(`/admin/coupons/${item._id}`,headers);await load()})};onMounted(load)
</script><style scoped>.manager{color:#effffb}.manager__head{display:flex;align-items:center;justify-content:space-between;margin-bottom:1rem}.manager__head span{color:#8fffee;font-size:.68rem;font-weight:800;letter-spacing:.14em}.manager h2{margin:.3rem 0 1rem}.manager__head .q-btn,.manager__cta{color:#03110f;background:linear-gradient(135deg,#8fffee,#13bc9d);font-weight:800}.manager__table{margin-top:1rem;background:rgba(4,24,25,.72);color:#effffb}.manager__dialog{width:min(92vw,32rem);color:#effffb;background:#041819}.manager__dialog :deep(.q-field__control){color:#effffb;background:rgba(4,24,25,.8)}.manager__dialog :deep(.q-field__native),.manager__dialog :deep(.q-field__label){color:#effffb}</style>
